"""
Step ID: step03
Step Name: fit_reverse_models
RQ: results/ch7/7.7.1
Generated: 2026-01-09

PURPOSE:
Fit reverse regression models (RAVLT/BVMT ~ REMEMVR) with bootstrap CIs and dual p-values

EXPECTED INPUTS:
  - results/ch7/7.7.1/data/step02_standardized_data.csv
    Columns: ['UID', 'REMEMVR_T', 'RAVLT_T', 'BVMT_T']

EXPECTED OUTPUTS:
  - results/ch7/7.7.1/data/step03_reverse_models.csv
    Columns: ['model', 'outcome', 'predictor', 'R2', 'adj_R2', 'beta', 'se',
              'ci_lower', 'ci_upper', 'p_uncorrected', 'p_bonferroni']

VALIDATION CRITERIA:
  - R² in [0, 1]
  - Beta coefficients reasonable (-5 to 5 range)
  - Bootstrap CIs bracket beta estimates

g_code REASONING:
- Approach: Fit 4 simple regressions, bootstrap CIs, apply Bonferroni correction
- Why this approach: Reverse prediction tests if VR memory predicts traditional tests
- Data flow: Load → Fit models → Bootstrap → Correct p-values → Save
- Expected performance: ~10 seconds (1000 bootstrap iterations)

IMPLEMENTATION NOTES:
- Analysis tool: tools.analysis_regression.fit_multiple_regression
- Bootstrap tool: tools.bootstrap.bootstrap_statistic
- Bonferroni: alpha=0.05/2=0.025 (2 models)
- Decision D068: Report BOTH p_uncorrected AND p_bonferroni
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np

PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

from tools.analysis_regression import fit_multiple_regression, bootstrap_regression_ci
from tools.bootstrap import bootstrap_statistic

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]
LOG_FILE = RQ_DIR / "logs" / "step03_reverse_models.log"

def log(msg):
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 03: Fit Reverse Regression Models")

        # STEP 1: Load standardized data
        log("[LOAD] Loading T-scored variables...")
        input_path = RQ_DIR / 'data' / 'step02_standardized_data.csv'
        df = pd.read_csv(input_path)
        log(f"[LOADED] {len(df)} participants")

        # STEP 2: Fit reverse regression models
        # Models: REMEMVR_T → each outcome (total scores + percent retention)
        models_to_fit = [
            ('RAVLT_reverse', 'RAVLT_T'),
            ('BVMT_reverse', 'BVMT_T'),
            ('RAVLT_PctRet_reverse', 'RAVLT_PctRet_T'),
            ('BVMT_PctRet_reverse', 'BVMT_PctRet_T'),
        ]

        n_tests = len(models_to_fit)
        log(f"[INFO] Fitting {n_tests} reverse models (Bonferroni alpha=0.05/{n_tests}={0.05/n_tests:.4f})")

        all_results = []

        for model_idx, (model_name, outcome_col) in enumerate(models_to_fit, 1):
            log(f"[MODEL {model_idx}] Fitting {outcome_col} ~ REMEMVR_T...")

            X = df[['REMEMVR_T']].values
            y = df[outcome_col].values

            model = fit_multiple_regression(X=X, y=y, feature_names=['REMEMVR_T'])

            log(f"[RESULT] R²={model['rsquared']:.4f}, adj_R²={model['rsquared_adj']:.4f}")
            log(f"[RESULT] Beta={model['coefficients']['REMEMVR_T']:.4f}, p={model['pvalues']['REMEMVR_T']:.4f}")

            # Bootstrap CIs
            log(f"[BOOTSTRAP] Computing 95% CIs for {model_name}...")
            boot = bootstrap_regression_ci(X=X, y=y, n_bootstrap=1000, seed=42)
            ci_lower = boot['ci_lower'][1]
            ci_upper = boot['ci_upper'][1]
            log(f"[BOOTSTRAP] Beta 95% CI: [{ci_lower:.4f}, {ci_upper:.4f}]")

            # Bonferroni correction
            p_uncorrected = model['pvalues']['REMEMVR_T']
            p_bonferroni = min(p_uncorrected * n_tests, 1.0)
            log(f"[CORRECTION] p_uncorrected={p_uncorrected:.4f}, p_bonferroni={p_bonferroni:.4f}")

            all_results.append({
                'model': model_name,
                'outcome': outcome_col,
                'predictor': 'REMEMVR_T',
                'R2': model['rsquared'],
                'adj_R2': model['rsquared_adj'],
                'beta': model['coefficients']['REMEMVR_T'],
                'se': model['std_errors']['REMEMVR_T'],
                'ci_lower': ci_lower,
                'ci_upper': ci_upper,
                'p_uncorrected': p_uncorrected,
                'p_bonferroni': p_bonferroni,
            })

        # STEP 3: Compile results
        log("[SAVE] Compiling model results...")
        results = pd.DataFrame(all_results)

        output_path = RQ_DIR / 'data' / 'step03_reverse_models.csv'
        results.to_csv(output_path, index=False, encoding='utf-8')
        log(f"[SAVED] {output_path}")

        # Summary
        log("[SUMMARY] Reverse prediction results:")
        for r in all_results:
            log(f"  {r['model']}: R²={r['R2']:.3f}, p_bonf={r['p_bonferroni']:.4f}")

        log("[SUCCESS] Step 03 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        import traceback
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
